#include <bits/stdc++.h>
#define int long long
#define INF 9999999999999
#define Mod 1000000007
#define lb(a) (a&(-a))
using namespace std;
int x[1000001],y[1000001];
int a[1000001],b[1000001];
int d[1000001],last[1000001];
int sum(int qq) 
{
    int ans=0,p=qq;
    while(p>0)
    {
    	ans+=x[p]*(qq+1)-y[p];
        p-=lb(p);
    }
    return ans;
}
void add(int qq,int d,int n) 
{
	int p=qq;
	while(p<=n)
	{
		x[p]=x[p]+d;
		y[p]=y[p]+(int)d*qq;
		p+=lb(p); 
	}
	return;
}
signed main() 
{
    int n;cin>>n;
    for(int i=1;i<=n;++i)
	{
		cin>>a[i];b[i-1]=a[i];
	}
    sort(b,b+n);
    int m=unique(b,b+n)-b;
    for(int i=1;i<=n;++i)
	{
        a[i]=lower_bound(b,b+m,a[i])-b;
        last[i]=d[a[i]];d[a[i]]=i;
    }
    int ans=0,cur=0;
    for(int i=1;i<=n;i++)
	{
        cur+=i-last[i]+((sum(i)-sum(last[i]))<<1);
        cur%=Mod;ans+=cur;
        add(last[i]+1,1,n);
        add(i+1,-1,n);
    }
    cout<<(ans%Mod);
    return 0;
}
